def min_cost_tickets(days, costs):
    if not days:
        return 0

    travel_days = set(days)
    max_day = max(travel_days)

    dp = [0] * (max_day + 1)

    cost_1_day, cost_7_day, cost_30_day = costs

    for i in range(1, max_day + 1):
        if i not in travel_days:
            dp[i] = dp[i-1]
        else:
            option1 = dp[i-1] + cost_1_day
            option2 = dp[max(0, i-7)] + cost_7_day
            option3 = dp[max(0, i-30)] + cost_30_day
            dp[i] = min(option1, option2, option3)

    return dp[max_day]
